(window.webpackJsonp=window.webpackJsonp||[]).push([[119],{1795:function(n){n.exports=JSON.parse("{\"content\":\"<p>\u539f\u6587\u94fe\u63a5\uff1ahttps://blog.csdn.net/ImwaterP/article/details/96282230</p>\\n<p>\u5904\u7406\u6570\u636e\u65f6\u7ecf\u5e38\u9700\u8981\u4ece\u6570\u7ec4\u4e2d\u968f\u673a\u62bd\u53d6\u5143\u7d20\uff0c\u8fd9\u65f6\u5019\u5c31\u9700\u8981\u7528\u5230np.random.choice()\u3002\u7136\u800cchoice\u7528\u6cd5\u7684\u5b98\u65b9\u89e3\u91ca\u5e76\u4e0d\u8be6\u7ec6\uff0c\u5c24\u5176\u662f\u5bf9replace\u53c2\u6570\u7684\u89e3\u91ca\uff0c\u4f8b\u5b50\u4e5f\u4e0d\u662f\u5f88\u5168\u9762\u3002\u56e0\u6b64\u7ecf\u8fc7\u53cd\u590d\u5b9e\u9a8c\uff0c\u6211\u8f83\u4e3a\u8be6\u7ec6\u7684\u603b\u7ed3\u51fa\u4e86\u4ed6\u7684\u7528\u6cd5\uff0c\u5e76\u7ed9\u51fa\u4e86\u8f83\u4e3a\u8be6\u7ec6\u7684\u4f7f\u7528\u4ee3\u7801\u4f8b\u5b50\u3002</p>\\n<p><strong>\u5b98\u65b9\u89e3\u91ca</strong>\uff1a<a href=\\\"https://docs.scipy.org/doc/numpy/reference/generated/numpy.random.choice.html\\\">https://docs.scipy.org/doc/numpy/reference/generated/numpy.random.choice.html</a></p>\\n<p><strong>\u4e0b\u9762\u662f\u6211\u81ea\u5df1\u7684\u603b\u7ed3</strong></p>\\n<pre class=\\\"hljs\\\"><code>#numpy.random.choice(a, size=None, replace=True, p=None)\\n#\u4ecea(\u53ea\u8981\u662fndarray\u90fd\u53ef\u4ee5\uff0c\u4f46\u5fc5\u987b\u662f\u4e00\u7ef4\u7684)\u4e2d\u968f\u673a\u62bd\u53d6\u6570\u5b57\uff0c\u5e76\u7ec4\u6210\u6307\u5b9a\u5927\u5c0f(size)\u7684\u6570\u7ec4\\n#replace:True\u8868\u793a\u53ef\u4ee5\u53d6\u76f8\u540c\u6570\u5b57\uff0cFalse\u8868\u793a\u4e0d\u53ef\u4ee5\u53d6\u76f8\u540c\u6570\u5b57\\n#\u6570\u7ec4p\uff1a\u4e0e\u6570\u7ec4a\u76f8\u5bf9\u5e94\uff0c\u8868\u793a\u53d6\u6570\u7ec4a\u4e2d\u6bcf\u4e2a\u5143\u7d20\u7684\u6982\u7387\uff0c\u9ed8\u8ba4\u4e3a\u9009\u53d6\u6bcf\u4e2a\u5143\u7d20\u7684\u6982\u7387\u76f8\u540c\u3002\\n</code></pre>\\n<p>\u9664\u4e86numpy\u4e2d\u7684\u6570\u7ec4\uff0cpython\u5185\u5efa\u7684list\uff08\u5217\u8868\uff09\u3001tuple\uff08\u5143\u7ec4\uff09\u4e5f\u53ef\u4ee5\u4f7f\u7528\u3002</p>\\n<pre class=\\\"hljs\\\"><code>&gt;&gt;&gt;np.random.choice(5)#\u4ece[0, 5)\u4e2d\u968f\u673a\u8f93\u51fa\u4e00\u4e2a\u968f\u673a\u6570\\n#\u76f8\u5f53\u4e8enp.random.randint(0, 5)\\n\\t2\\n\\n&gt;&gt;&gt;np.random.choice(5, 3)#\u5728[0, 5)\u5185\u8f93\u51fa\u4e94\u4e2a\u6570\u5b57\u5e76\u7ec4\u6210\u4e00\u7ef4\u6570\u7ec4\uff08ndarray\uff09\\n#\u76f8\u5f53\u4e8enp.random.randint(0, 5, 3)\\n\\tarray([1, 4, 1])\\n</code></pre>\\n<pre class=\\\"hljs\\\"><code>L = [1, 2, 3, 4, 5]#list\u5217\u8868\\nT = (2, 4, 6, 2)#tuple\u5143\u7ec4\\nA = np.array([4, 2, 1])#numpy,array\u6570\u7ec4,\u5fc5\u987b\u662f\u4e00\u7ef4\u7684\\nA0 = np.arange(10).reshape(2, 5)#\u4e8c\u7ef4\u6570\u7ec4\u4f1a\u62a5\u9519\\n\\n&gt;&gt;&gt;np.random.choice(L, 5)\\n\\tarray([3, 5, 2, 1, 5])\\n\\t\\n&gt;&gt;&gt;np.random.choice(T, 5)\\n\\tarray([2, 2, 2, 4, 2])\\n \\n&gt;&gt;&gt;np.random.choice(A, 5)\\n\\tarray([1, 4, 2, 2, 1])\\n\\n&gt;&gt;&gt;np.random.choice(A0, 5)#\u5982\u679c\u662f\u4e8c\u7ef4\u6570\u7ec4\uff0c\u4f1a\u62a5\u9519\\n\\tValueError: 'a' must be 1-dimensional\\n</code></pre>\\n<ul>\\n<li><strong>\u53c2\u6570replace</strong> \u7528\u6765\u8bbe\u7f6e\u662f\u5426\u53ef\u4ee5\u53d6\u76f8\u540c\u5143\u7d20\uff1a True\u8868\u793a\u53ef\u4ee5\u53d6\u76f8\u540c\u6570\u5b57\uff1b False\u8868\u793a\u4e0d\u53ef\u4ee5\u53d6\u76f8\u540c\u6570\u5b57\u3002 \u9ed8\u8ba4\u662fTrue</li>\\n</ul>\\n<pre class=\\\"hljs\\\"><code>np.random.choice(5, 6, replace=True)#\u53ef\u4ee5\u770b\u5230\u6709\u76f8\u540c\u5143\u7d20\\n\\tarray([3, 4, 1, 1, 0, 3])\\nnp.random.choice(5, 6, replace=False)#\u4f1a\u62a5\u9519\uff0c\u56e0\u4e3a\u4e94\u4e2a\u6570\u5b57\u4e2d\u53d6\u516d\u4e2a\uff0c\u4e0d\u53ef\u80fd\u4e0d\u53d6\u5230\u91cd\u590d\u7684\u6570\u5b57\\n\\tValueError: Cannot take a larger sample than population when 'replace=False'\\n</code></pre>\\n<ul>\\n<li><strong>\u53c2\u6570p</strong></li>\\n</ul>\\n<p>p\u5b9e\u9645\u662f\u4e2a\u6570\u7ec4\uff0c\u5927\u5c0f\uff08size\uff09\u5e94\u8be5\u4e0e\u6307\u5b9a\u7684a\u76f8\u540c\uff0c\u7528\u6765\u89c4\u5b9a\u9009\u53d6a\u4e2d\u6bcf\u4e2a\u5143\u7d20\u7684\u6982\u7387\uff0c\u9ed8\u8ba4\u4e3a\u6982\u7387\u76f8\u540c\uff0c\u603b\u548c\u4e3a1</p>\\n<pre class=\\\"hljs\\\"><code>&gt;&gt;&gt; aa_milne_arr = ['pooh', 'rabbit', 'piglet', 'Christopher']\\n&gt;&gt;&gt; np.random.choice(aa_milne_arr, 5, p=[0.5, 0.1, 0.1, 0.3])\\n\\tarray(['pooh', 'pooh', 'pooh', 'Christopher', 'piglet'], dtype='|S11')\\n#\u53ef\u4ee5\u770b\u5230\uff0c\u2018pooh\u2019\u88ab\u9009\u53d6\u7684\u6982\u7387\u660e\u663e\u6bd4\u5176\u4ed6\u51e0\u4e2a\u9ad8\u5f88\u591a\\n</code></pre>\\n\"}")}}]);